$capabilities = & $getCap;
foreach( $selector in $caps ) {
    $found = $capabilities | Where-Object -FilterScript { ($_.Name -split '~')[0] -eq $selector }
    if( $found ) { $found | Remove-WindowsCapability -Online -ErrorAction 'Continue' }
}

